class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9: empty env vars now return "" instead of null.
        // Use string.IsNullOrEmpty to treat both "not set" and "empty" as default,
        // preserving the .NET 8 behavior where empty was indistinguishable from unset.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (string.IsNullOrEmpty(val))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

