using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now sets the UTF-8 flag on entry names.
        // The legacy Java consumer expects Shift-JIS, so use the overload
        // that accepts an explicit encoding to suppress the UTF-8 flag.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9: [FromKeyedServices] no longer falls back to non-keyed registrations.
// Register as a keyed service to match the controller's attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

